import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using gemini-3-flash-preview for general text explanations related to physics
export const generatePhysicsExplanation = async (
  topic: string, 
  velocity: number, 
  gamma: number
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Explain the concept of ${topic} in the context of Special Relativity. 
      Specifically, explain what happens when an object travels at ${velocity * 100}% the speed of light (0.99c max), 
      resulting in a Lorentz factor (gamma) of ${gamma.toFixed(2)}. 
      Keep the explanation concise (under 150 words), engaging, and strictly scientifically accurate. 
      Use simple analogies.`
    });
    // Correctly accessing the text property from the response object
    return response.text || "I couldn't generate an explanation at this moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error connecting to the relativity database (AI service unavailable).";
  }
};

// Using gemini-3-pro-preview for advanced reasoning and persona-based chat interaction
export const chatWithEinstein = async (history: {role: string, parts: {text: string}[]}[], message: string): Promise<string> => {
    try {
        const chat = ai.chats.create({
            model: 'gemini-3-pro-preview',
            config: {
                systemInstruction: `You are Albert Einstein. You are helpful, slightly witty, and deeply knowledgeable about physics. 
                You are talking to a student exploring Special Relativity. 
                Explain concepts clearly. If asked about math, use plain text or standard math symbols, do not use complex LaTeX blocks as they might not render.
                Keep responses relatively short and conversational.`,
            },
            history: history
        });

        const result = await chat.sendMessage({ message });
        // Correctly accessing the text property from the response object
        return result.text || "I am currently lost in thought.";
    } catch (error) {
        console.error("Gemini Chat Error:", error);
        return "My apologies, I seem to have lost my train of thought (AI service error).";
    }
}

import { GoogleGenAI, Modality } from "@google/genai";
import { VoicePersona } from "../types";
import { decodeAudioData, playAudioBuffer } from "../utils/audioUtils";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PERSONA_CONFIGS = {
  HEADMASTER: {
    voice: 'Fenrir',
    promptPrefix: "You are a strict, authoritative Physics Headmaster with a deep voice. Read the following explanation in a lecturing, serious, but educational tone: "
  },
  SISTER: {
    voice: 'Kore',
    promptPrefix: "You are a gentle, intellectual, and slightly flirtatious senior female student. Read the following explanation in a soft, caring, and engaging voice: "
  },
  REBEL: {
    voice: 'Puck',
    promptPrefix: "You are a dismissive, arrogant rich playboy who thinks he knows everything. Read the following explanation in a mocking, bored tone, starting with 'You don't even know this?': "
  }
};

export const speakExplanation = async (text: string, persona: VoicePersona) => {
  try {
    const config = PERSONA_CONFIGS[persona];

    // Updated to use Modality.AUDIO and correct responseModalities array as per guidelines
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `${config.promptPrefix} "${text}"` }] }],
      config: {
        responseModalities: [Modality.AUDIO], 
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: config.voice },
            },
        },
      },
    });

    // Access base64 audio data from candidates
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (base64Audio) {
      const audioBuffer = await decodeAudioData(base64Audio, 24000);
      playAudioBuffer(audioBuffer);
    } else {
      console.warn("TTS: No audio data received in response");
    }
  } catch (error) {
    console.error("TTS Service Error:", error);
    // Silent fail in UI is better than crashing, but we log to console
  }
};

