    if (this.user) {
      this.user.learningStyle = style;
      this.user.learningScores = scores;
      await this.saveUser(this.user);
    }
  }

  public async logEvent(event: Omit<AnalyticsEvent, 'userId' | 'timestamp' | 'interEventTime' | 'sequenceIndex'>) {
    if (!this.user) return;

    const now = Date.now();
    const interTime = (now - this.lastEventTime) / 1000;
    this.eventSequence++;
    sessionStorage.setItem(SESSION_SEQ_KEY, this.eventSequence.toString());

    const fullEvent: AnalyticsEvent = {
      ...event,
      userId: this.user.id,
      timestamp: now,
      interEventTime: interTime,
      sequenceIndex: this.eventSequence
    };

    this.lastEventTime = now;

    // Persist to Supabase
    const { error } = await supabase
      .from('events')
      .insert({
        user_id: fullEvent.userId,
        event_type: fullEvent.eventType,
        target: fullEvent.target,
        value: fullEvent.value,
        inter_event_time: fullEvent.interEventTime,
        sequence_index: fullEvent.sequenceIndex,
        metadata: fullEvent.metadata,
