export const QuizPage: React.FC = () => {
  usePageTracking("QuizPage");
  const { trackClick } = useAnalytics();

  const [currentQuestionIdx, setCurrentQuestionIdx] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [quizFinished, setQuizFinished] = useState(false);

  const currentQuestion = QUESTIONS[currentQuestionIdx];

  const handleSelect = (idx: number) => {
    if (isAnswered) return;
    setSelectedOption(idx);
  };

  const handleSubmit = () => {
    if (selectedOption === null) return;
    setIsAnswered(true);
    const isCorrect = selectedOption === currentQuestion.correctIndex;
    if (isCorrect) setScore(prev => prev + 1);
  };

  const handleNext = async () => {
    if (currentQuestionIdx < QUESTIONS.length - 1) {
      setCurrentQuestionIdx(prev => prev + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      setQuizFinished(true);
      const user = db.getUser();
      if (user) {
        await db.saveQuizResult({
          userId: user.id,
          score: score,
          totalQuestions: QUESTIONS.length
        });
      }
    }
  };

  const handleRetry = () => {
    setCurrentQuestionIdx(0);
    setScore(0);
    setSelectedOption(null);
    setIsAnswered(false);
    setQuizFinished(false);
  };

  if (quizFinished) {
    const percentage = (score / QUESTIONS.length) * 100;
    return (
      <div className="min-h-[600px] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-space-800 rounded-2xl border border-space-700 p-8 text-center animate-in zoom-in-95">
           <Award size={64} className="text-cyan-400 mx-auto mb-6" />
           <h2 className="text-3xl font-bold text-white mb-2">Quiz Complete!</h2>
           <div className="text-6xl font-bold text-cyan-400 mb-8">{percentage}%</div>
           <Button onClick={handleRetry} className="w-full flex items-center justify-center gap-2">
              <RotateCcw size={18} /> Retry Quiz
           </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto p-4 md:py-12">
      <div className="flex justify-between items-center mb-6">
         <h1 className="text-2xl font-bold text-white">Question {currentQuestionIdx + 1}/{QUESTIONS.length}</h1>
         <div className="text-cyan-400 font-mono text-lg font-bold">Score: {score}</div>
      </div>

      <div className="bg-space-800 rounded-2xl border border-space-700 p-8 shadow-xl">
         <h2 className="text-xl text-white mb-8 leading-relaxed">{currentQuestion.text}</h2>
         <div className="space-y-3">
            {currentQuestion.options.map((option, idx) => (
               <button
                 key={idx}
                 onClick={() => handleSelect(idx)}
                 disabled={isAnswered}
                 className={`w-full text-left p-4 rounded-xl border transition-all ${
                   isAnswered 
                    ? idx === currentQuestion.correctIndex ? 'bg-green-900/40 border-green-500' : idx === selectedOption ? 'bg-red-900/40 border-red-500' : 'bg-space-900 border-space-600'
                    : selectedOption === idx ? 'bg-cyan-900/40 border-cyan-500' : 'bg-space-900 border-space-600 hover:bg-space-700'
                 }`}
               >
                  {option}
               </button>
            ))}
         </div>
         {isAnswered ? (
            <div className="mt-8 pt-6 border-t border-space-600">
                <p className="text-slate-300 text-sm mb-6">{currentQuestion.explanation}</p>
                <div className="flex justify-end"><Button onClick={handleNext}>Next Question</Button></div>
            </div>
         ) : (
            <div className="mt-8 flex justify-end"><Button onClick={handleSubmit} disabled={selectedOption === null}>Submit Answer</Button></div>
         )}
      </div>
    </div>
  );
};

